using System;
using System.IO;
using System.Collections.Generic;
using System.Drawing;
using System.Drawing.Drawing2D;
using System.Drawing.Imaging;
using System.IO;
using System.Windows.Forms;

namespace Tunetoon.Forms
{
    public class MazeGame : UserControl
    {
        private const int CS = 13;
        private const int COLS = 24;
        private const int ROWS = 23;

        private struct Cell
        {
            public bool[] Walls;
            public bool Visited;
        }

        private Cell[] _maze;
        private Point  _player;
        private Point  _exit;
        private bool   _won;
        private bool   _started;
        private int    _elapsed;
        private Timer  _timer;
        private Random _rng = new();

        // Direção do jogador: 0=esq, 1=dir, 2=cima, 3=baixo
        private int _dir = 0;

        // Pontos persistentes
        private int _organicPoints      = 0;
        private int _savedOrganicPoints = 0; // valor salvo em disco; restaurado ao morrer
        private int _laffPoints         = 0;
        private const int MAX_ORGANIC = 9999;
        private const int MAX_LAFF    = 140;
        private static readonly string SAVE_PATH =
            System.IO.Path.Combine(
                Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData),
                "Tunetoon", "maze_points.dat");

        // Power-up (árvore): velocidade + matar fantasmas por 8s
        private bool   _powerUpActive  = false;
        private Timer  _powerUpTimer;
        private int    _powerUpSeconds = 0; // segundos restantes exibidos

        // Imagens
        private Image _imgPlayer;
        private Image _imgBoss;

        // Árvores: posições fixas (células livres espalhadas)
        private List<Point> _trees = new();

        // Fantasmas estilo Pac-Man
        private List<Point> _ghosts = new();
        private static readonly Color[] GHOST_COLORS = {
            Color.FromArgb(220,  60,  60),   // vermelho
            Color.FromArgb( 60, 180, 220),   // ciano
            Color.FromArgb(220, 120, 220),   // rosa
            Color.FromArgb(240, 180,  40),   // laranja
        };
        private Timer _ghostTimer;

        private static readonly string PLAYER_B64 = "";
        private static readonly string BOSS_B64   = "";

        public MazeGame()
        {
            Width          = 330;
            Height         = 331;
            DoubleBuffered = true;
            BackColor      = SystemColors.Window;
            TabStop        = true;

            _timer = new Timer { Interval = 1000 };
            _timer.Tick += (_, __) => { if (!_won) { _elapsed++; Invalidate(); } };

            _ghostTimer = new Timer { Interval = 380 };
            _ghostTimer.Tick += (_, __) => { if (!_won && _started) MoveGhosts(); };

            _powerUpTimer = new Timer { Interval = 1000 };
            _powerUpTimer.Tick += (_, __) =>
            {
                if (_powerUpSeconds > 0) _powerUpSeconds--;
                if (_powerUpSeconds <= 0)
                {
                    _powerUpActive = false;
                    _ghostTimer.Interval = 380; // restaura velocidade fantasma
                    _powerUpTimer.Stop();
                }
                Invalidate();
            };

            KeyDown    += OnKeyDown;
            MouseClick += (_, __) => { Focus(); };

            // Carrega imagens
            try
            {
                _imgPlayer = LoadFromBase64(PLAYER_B64);
                _imgBoss   = LoadFromBase64(BOSS_B64);
            }
            catch { }

            Init();
            LoadPoints();
        }

        private Image LoadFromBase64(string b64)
        {
            var bytes = Convert.FromBase64String(b64);
            return Image.FromStream(new MemoryStream(bytes));
        }

        public void ProcessMazeKey(KeyEventArgs e) => OnKeyDown(this, e);

        private void Init()
        {
            _maze = new Cell[COLS * ROWS];
            for (int i = 0; i < _maze.Length; i++)
                _maze[i].Walls = new bool[] { true, true, true, true };

            GenerateMaze(0, 0);
            _player  = new Point(0, 0);
            _exit    = new Point(COLS - 1, ROWS - 1);
            _won     = false;
            _started = false;
            _elapsed = 0;
            _dir     = 3; // inicia virado para baixo
            _timer.Stop();
            _ghostTimer.Stop();
            _powerUpActive = false;
            _powerUpTimer?.Stop();

            PlaceTrees();
            PlaceGhosts();
            AddExtraPaths(); // múltiplas saídas/caminhos
            Invalidate();
        }

        private void PlaceTrees()
        {
            _trees.Clear();
            var candidates = new List<Point>();
            for (int y = 0; y < ROWS; y++)
                for (int x = 0; x < COLS; x++)
                {
                    var p = new Point(x, y);
                    if (p == _player || p == _exit) continue;
                    var c = _maze[Idx(x, y)];
                    int walls = (c.Walls[0]?1:0)+(c.Walls[1]?1:0)+(c.Walls[2]?1:0)+(c.Walls[3]?1:0);
                    if (walls >= 2) candidates.Add(p);
                }
            // Embaralha e pega exatamente 15
            for (int i = candidates.Count - 1; i > 0; i--)
            {
                int j = _rng.Next(i + 1);
                var tmp = candidates[i]; candidates[i] = candidates[j]; candidates[j] = tmp;
            }
            for (int i = 0; i < Math.Min(20, candidates.Count); i++)
                _trees.Add(candidates[i]);
        }

        // ── Caminhos extras: abre passagens sutis espalhadas pelo labirinto ────
        private void AddExtraPaths()
        {
            int[] dx2 = { 0, 1, 0, -1 };
            int[] dy2 = { -1, 0, 1, 0 };
            int[] opp  = { 2, 3, 0, 1 };

            // Apenas ~8% das células ganham uma passagem extra aleatória,
            // priorizando levemente a região central mas sem destruir a estrutura.
            int extras = (COLS * ROWS) / 12; // ~46 passagens extras
            int attempts = extras * 10;

            int cx = COLS / 2;
            int cy = ROWS / 2;

            for (int i = 0; i < attempts && extras > 0; i++)
            {
                // 60% de chance de sortear na região central (±4 células do centro)
                int x, y;
                if (_rng.Next(10) < 6)
                {
                    x = cx + _rng.Next(-4, 5);
                    y = cy + _rng.Next(-4, 5);
                }
                else
                {
                    x = _rng.Next(1, COLS - 1);
                    y = _rng.Next(1, ROWS - 1);
                }

                if (x < 0 || x >= COLS || y < 0 || y >= ROWS) continue;

                int d = _rng.Next(4);
                int nx2 = x + dx2[d], ny2 = y + dy2[d];
                if (nx2 < 0 || nx2 >= COLS || ny2 < 0 || ny2 >= ROWS) continue;
                if (!_maze[Idx(x, y)].Walls[d]) continue;

                _maze[Idx(x, y)].Walls[d] = false;
                _maze[Idx(nx2, ny2)].Walls[opp[d]] = false;
                extras--;
            }
        }

        // ── Geração DFS ───────────────────────────────────────────────────────
        private void GenerateMaze(int sx, int sy)
        {
            var stack = new Stack<Point>();
            _maze[Idx(sx, sy)].Visited = true;
            stack.Push(new Point(sx, sy));

            while (stack.Count > 0)
            {
                var cur = stack.Peek();
                var nbs = GetUnvisitedNeighbors(cur.X, cur.Y);
                if (nbs.Count == 0) { stack.Pop(); continue; }
                var next = nbs[_rng.Next(nbs.Count)];
                RemoveWall(cur, next);
                _maze[Idx(next.X, next.Y)].Visited = true;
                stack.Push(next);
            }
        }

        private List<Point> GetUnvisitedNeighbors(int x, int y)
        {
            var list = new List<Point>();
            if (y > 0      && !_maze[Idx(x, y-1)].Visited) list.Add(new Point(x, y-1));
            if (y < ROWS-1 && !_maze[Idx(x, y+1)].Visited) list.Add(new Point(x, y+1));
            if (x > 0      && !_maze[Idx(x-1, y)].Visited) list.Add(new Point(x-1, y));
            if (x < COLS-1 && !_maze[Idx(x+1, y)].Visited) list.Add(new Point(x+1, y));
            return list;
        }

        private void RemoveWall(Point a, Point b)
        {
            int dx = b.X-a.X, dy = b.Y-a.Y;
            if (dx ==  1) { _maze[Idx(a.X,a.Y)].Walls[1]=false; _maze[Idx(b.X,b.Y)].Walls[3]=false; }
            if (dx == -1) { _maze[Idx(a.X,a.Y)].Walls[3]=false; _maze[Idx(b.X,b.Y)].Walls[1]=false; }
            if (dy ==  1) { _maze[Idx(a.X,a.Y)].Walls[2]=false; _maze[Idx(b.X,b.Y)].Walls[0]=false; }
            if (dy == -1) { _maze[Idx(a.X,a.Y)].Walls[0]=false; _maze[Idx(b.X,b.Y)].Walls[2]=false; }
        }

        private int Idx(int x, int y) => y * COLS + x;

        // ── Movimento ─────────────────────────────────────────────────────────
        private void Move(int dx, int dy)
        {
            if (_won) return;
            if (!_started) { _started = true; _timer.Start(); _ghostTimer.Start(); }

            // Atualiza direção
            if      (dx == -1) _dir = 0; // esquerda
            else if (dx ==  1) _dir = 1; // direita
            else if (dy == -1) _dir = 2; // cima
            else if (dy ==  1) _dir = 3; // baixo

            var c = _maze[Idx(_player.X, _player.Y)];
            int nx = _player.X + dx, ny = _player.Y + dy;

            if (dx ==  1 && !c.Walls[1]) _player.X++;
            if (dx == -1 && !c.Walls[3]) _player.X--;
            if (dy ==  1 && !c.Walls[2]) _player.Y++;
            if (dy == -1 && !c.Walls[0]) _player.Y--;

            // Colidiu com árvore → +1 Organic Point, árvore desaparece, power-up 8s
            if (_trees.Contains(_player))
            {
                _trees.Remove(_player);
                if (_organicPoints < MAX_ORGANIC)
                    _organicPoints = Math.Min(MAX_ORGANIC, _organicPoints + 1);
                // Organic Points só são salvos ao completar o labirinto
                // Ativa power-up: velocidade dobrada e pode derrotar fantasmas
                _powerUpActive  = true;
                _powerUpSeconds = 8;
                _ghostTimer.Interval = 760; // fantasmas mais lentos durante power-up
                _powerUpTimer.Start();
            }

            // Chegou na saída → +1 Laff Point
            if (_player == _exit)
            {
                _won = true;
                _timer.Stop();
                _ghostTimer.Stop();
                if (_laffPoints < MAX_LAFF)
                    _laffPoints = Math.Min(MAX_LAFF, _laffPoints + 1);
                SavePoints();
            }

            // Colidiu com fantasma
            if (!_won && _ghosts.Contains(_player))
            {
                if (_powerUpActive)
                {
                    // Derrota o fantasma: +2 Organic Points, remove fantasma
                    _ghosts.Remove(_player);
                    _organicPoints = Math.Min(MAX_ORGANIC, _organicPoints + 2);
                    // Organic Points só são salvos ao completar o labirinto
                    Invalidate();
                    return;
                }
                _laffPoints         = Math.Max(0, _laffPoints - 1);
                _organicPoints      = _savedOrganicPoints; // descarta pontos nao confirmados
                SavePoints();
                Init();
                return;
            }
            Invalidate();
        }

        private void OnKeyDown(object sender, KeyEventArgs e)
        {
            switch (e.KeyCode)
            {
                case Keys.Up:    case Keys.W: Move( 0,-1); break;
                case Keys.Down:  case Keys.S: Move( 0, 1); break;
                case Keys.Left:  case Keys.A: Move(-1, 0); break;
                case Keys.Right: case Keys.D: Move( 1, 0); break;
                case Keys.R: Init(); break;
            }
            e.Handled = true;
        }

        // ── Desenho ───────────────────────────────────────────────────────────
        protected override void OnPaint(PaintEventArgs e)
        {
            var g = e.Graphics;
            g.Clear(BackColor);
            g.SmoothingMode = SmoothingMode.AntiAlias;

            using var wallPen   = new Pen(Color.FromArgb(180, 180, 180), 1f);
            using var pathBrush = new SolidBrush(Color.FromArgb(248, 248, 248));

            // Células
            for (int y = 0; y < ROWS; y++)
            {
                for (int x = 0; x < COLS; x++)
                {
                    int px = x * CS, py = y * CS;
                    var c = _maze[Idx(x, y)];
                    g.FillRectangle(pathBrush, px, py, CS, CS);
                    if (c.Walls[0]) g.DrawLine(wallPen, px,    py,    px+CS, py);
                    if (c.Walls[1]) g.DrawLine(wallPen, px+CS, py,    px+CS, py+CS);
                    if (c.Walls[2]) g.DrawLine(wallPen, px,    py+CS, px+CS, py+CS);
                    if (c.Walls[3]) g.DrawLine(wallPen, px,    py,    px,    py+CS);
                }
            }

            // Árvores
            DrawTrees(g);

            // Fantasmas
            DrawGhosts(g);

            // Boss (exit)
            DrawBoss(g);

            // Jogador
            DrawPlayer(g);

            // Scoreboard — 1 linha compacta
            int sy2 = ROWS * CS + 3;
            using var sf2 = new Font("Segoe UI", 7.5f);
            int m = _elapsed / 60, s = _elapsed % 60;
            string timeStr = $"{m:D2}:{s:D2}";
            string powerInfo = _powerUpActive ? $"  ⚡{_powerUpSeconds}s" : "";
            string status = _won
                ? $"Escaped! {timeStr}  R=new"
                : _started
                    ? $"{timeStr}{powerInfo}  WASD/arrows  R=new"
                    : "WASD or arrows  |  R=new";
            string pts = $"Organic: {_organicPoints}pts    {_laffPoints} Laff Points";
            // Linha de status (esquerda)
            var statusBrush = _powerUpActive ? Brushes.Orange : (_won ? Brushes.DarkGreen : Brushes.Gray);
            g.DrawString(status, sf2, statusBrush, 2, sy2);
            // Pontos (direita)
            var ptsSize = g.MeasureString(pts, sf2);
            g.DrawString(pts, sf2, _won ? Brushes.DarkGreen : Brushes.Gray, Width - ptsSize.Width - 2, sy2);

            // Mensagem de vitória "Cog Battle!"
            if (_won)
            {
                int mw = COLS * CS;
                int mh = ROWS * CS;
                using var overlay = new SolidBrush(Color.FromArgb(160, 0, 0, 0));
                g.FillRectangle(overlay, 0, 0, mw, mh);
                using var bigFont = new Font("Segoe UI", 22f, FontStyle.Bold);
                string msg = "Cog Battle!";
                var sz = g.MeasureString(msg, bigFont);
                float tx = (mw - sz.Width)  / 2f;
                float ty = (mh - sz.Height) / 2f;
                g.DrawString(msg, bigFont, Brushes.Black, tx + 2, ty + 2);
                using var yellow = new SolidBrush(Color.FromArgb(255, 220, 50));
                g.DrawString(msg, bigFont, yellow, tx, ty);
            }
        }

        private void PlaceGhosts()
        {
            _ghosts.Clear();
            // Posições de largada: 4 cantos opostos ao player (0,0)
            var starts = new Point[]
            {
                new Point(COLS-1, 0),
                new Point(0, ROWS-1),
                new Point(COLS-1, ROWS/2),
                new Point(COLS/2, ROWS-1),
            };
            foreach (var s in starts)
                _ghosts.Add(s);
        }

        // BFS: retorna próximo passo do fantasma em direção ao player
        private Point BfsStep(Point from, Point target)
        {
            if (from == target) return from;
            var prev = new Dictionary<Point, Point>();
            var queue = new Queue<Point>();
            queue.Enqueue(from);
            prev[from] = from;

            int[] dx = { 0, 0, -1, 1 };
            int[] dy = { -1, 1, 0, 0 };
            // wall indices: 0=cima,2=baixo,3=esq,1=dir
            int[] wallIdx = { 0, 2, 3, 1 };

            while (queue.Count > 0)
            {
                var cur = queue.Dequeue();
                if (cur == target) break;
                var cell = _maze[Idx(cur.X, cur.Y)];
                for (int d = 0; d < 4; d++)
                {
                    if (cell.Walls[wallIdx[d]]) continue;
                    var nb = new Point(cur.X + dx[d], cur.Y + dy[d]);
                    if (nb.X < 0 || nb.X >= COLS || nb.Y < 0 || nb.Y >= ROWS) continue;
                    if (prev.ContainsKey(nb)) continue;
                    prev[nb] = cur;
                    queue.Enqueue(nb);
                }
            }

            if (!prev.ContainsKey(target)) return from; // sem caminho
            // Reconstrói caminho de target → from
            var step = target;
            while (prev[step] != from)
                step = prev[step];
            return step;
        }

        private void MoveGhosts()
        {
            for (int i = 0; i < _ghosts.Count; i++)
            {
                Point next;
                if (_powerUpActive)
                    next = BfsFleeStep(_ghosts[i], _player); // foge do player
                else
                    next = BfsStep(_ghosts[i], _player);     // persegue o player
                _ghosts[i] = next;
            }
            // Verifica colisão após mover
            if (_ghosts.Contains(_player))
            {
                if (_powerUpActive)
                {
                    // Remove todos os fantasmas que colidiram
                    int removed = _ghosts.RemoveAll(g => g == _player);
                    _organicPoints = Math.Min(MAX_ORGANIC, _organicPoints + 2 * removed);
                    // Organic Points só são salvos ao completar o labirinto
                    Invalidate();
                    return;
                }
                _laffPoints         = Math.Max(0, _laffPoints - 1);
                _organicPoints      = _savedOrganicPoints; // descarta pontos nao confirmados
                SavePoints();
                Init();
                return;
            }
            Invalidate();
        }

        // BFS fuga: retorna o próximo passo que MAXIMIZA a distância do player
        private Point BfsFleeStep(Point from, Point player)
        {
            if (from == player) return from;

            // Calcula distância BFS de todos os nós até o player
            var dist = new Dictionary<Point, int>();
            var queue = new Queue<Point>();
            dist[player] = 0;
            queue.Enqueue(player);

            int[] dx = { 0, 0, -1, 1 };
            int[] dy = { -1, 1, 0, 0 };
            int[] wallIdx = { 0, 2, 3, 1 };

            while (queue.Count > 0)
            {
                var cur = queue.Dequeue();
                var cell = _maze[Idx(cur.X, cur.Y)];
                for (int d = 0; d < 4; d++)
                {
                    if (cell.Walls[wallIdx[d]]) continue;
                    var nb = new Point(cur.X + dx[d], cur.Y + dy[d]);
                    if (nb.X < 0 || nb.X >= COLS || nb.Y < 0 || nb.Y >= ROWS) continue;
                    if (dist.ContainsKey(nb)) continue;
                    dist[nb] = dist[cur] + 1;
                    queue.Enqueue(nb);
                }
            }

            // Escolhe o vizinho acessível com MAIOR distância do player
            var fromCell = _maze[Idx(from.X, from.Y)];
            Point best = from;
            int bestDist = dist.ContainsKey(from) ? dist[from] : 0;
            for (int d = 0; d < 4; d++)
            {
                if (fromCell.Walls[wallIdx[d]]) continue;
                var nb = new Point(from.X + dx[d], from.Y + dy[d]);
                if (nb.X < 0 || nb.X >= COLS || nb.Y < 0 || nb.Y >= ROWS) continue;
                if (!dist.ContainsKey(nb)) continue;
                if (dist[nb] > bestDist)
                {
                    bestDist = dist[nb];
                    best = nb;
                }
            }
            return best;
        }

        private void DrawGhosts(Graphics g)
        {
            for (int i = 0; i < _ghosts.Count; i++)
            {
                var gh = _ghosts[i];
                int px = gh.X * CS + 1;
                int py = gh.Y * CS + 1;
                int w  = CS - 2;
                int h  = CS - 2;
                // Quando power-up ativo, fantasmas ficam azul-escuro (assustados)
                var col = _powerUpActive
                    ? Color.FromArgb(30, 30, 180)
                    : GHOST_COLORS[i % GHOST_COLORS.Length];

                // Corpo arredondado (topo semicírculo + base serrilhada)
                using var body = new SolidBrush(col);
                // Semicírculo topo
                g.FillEllipse(body, px, py, w, w);
                // Retângulo meio-baixo
                g.FillRectangle(body, px, py + w/2, w, h - w/2);
                // Serrilha base (3 pontinhos)
                int notch = w / 3;
                using var bg = new SolidBrush(BackColor);
                for (int n = 0; n < 3; n++)
                    g.FillEllipse(bg, px + n * notch, py + h - notch/2 - 1, notch, notch/2 + 1);

                // Olhos
                int eyeR = Math.Max(1, w / 6);
                int eyeY = py + h / 3;
                g.FillEllipse(Brushes.White, px + w/4 - eyeR,     eyeY, eyeR*2, eyeR*2);
                g.FillEllipse(Brushes.White, px + 3*w/4 - eyeR,   eyeY, eyeR*2, eyeR*2);
                g.FillEllipse(Brushes.DarkBlue, px + w/4 - eyeR/2,   eyeY + eyeR/2, eyeR, eyeR);
                g.FillEllipse(Brushes.DarkBlue, px + 3*w/4 - eyeR/2, eyeY + eyeR/2, eyeR, eyeR);
            }
        }

        private void DrawTrees(Graphics g)
        {
            foreach (var t in _trees)
            {
                int px = t.X * CS + CS/2;
                int py = t.Y * CS + CS/2;
                int r  = CS / 2 - 1;

                // Tronco
                using var trunk = new SolidBrush(Color.FromArgb(101, 67, 33));
                g.FillRectangle(trunk, px-1, py, 2, r);

                // Copa (triângulo verde)
                var pts = new Point[]
                {
                    new Point(px,   py - r),
                    new Point(px-r, py + 1),
                    new Point(px+r, py + 1),
                };
                using var leaf = new SolidBrush(Color.FromArgb(34, 139, 34));
                g.FillPolygon(leaf, pts);
                using var leafPen = new Pen(Color.FromArgb(0, 100, 0), 0.5f);
                g.DrawPolygon(leafPen, pts);
            }
        }

        private void DrawBoss(Graphics g)
        {
            int px = _exit.X * CS;
            int py = _exit.Y * CS;

            if (_imgBoss != null)
            {
                int size   = (int)(CS * 1.6);
                int offset = (size - CS) / 2;
                g.DrawImage(_imgBoss, px - offset, py - offset, size, size);
            }
            else
            {
                g.FillRectangle(Brushes.DarkRed, px+1, py+1, CS-2, CS-2);
            }
        }

        private void DrawPlayer(Graphics g)
        {
            int px = _player.X * CS;
            int py = _player.Y * CS;

            // Halo amarelo quando power-up ativo
            if (_powerUpActive)
            {
                using var halo = new SolidBrush(Color.FromArgb(80, 255, 215, 0));
                g.FillEllipse(halo, px - 2, py - 2, CS + 4, CS + 4);
            }

            if (_imgPlayer != null)
            {
                g.InterpolationMode = InterpolationMode.HighQualityBicubic;

                // Salva estado para rotação
                var state = g.Save();
                int cx = px + CS / 2;
                int cy = py + CS / 2;

                // Rotação baseada na direção
                // Imagem original olha para esquerda (dir=0 = sem rotação)
                float angle = _dir switch
                {
                    0 => 0f,    // esquerda — original
                    1 => 180f,  // direita — espelha horizontal via rotação
                    2 => 90f,   // cima
                    3 => 270f,  // baixo
                    _ => 0f
                };

                g.TranslateTransform(cx, cy);
                if (_dir == 1)
                {
                    // Espelha horizontalmente para direita
                    g.ScaleTransform(-1, 1);
                }
                else
                {
                    g.RotateTransform(angle);
                }
                int imgSize = (int)(CS * 1.6);
                g.DrawImage(_imgPlayer, -imgSize / 2, -imgSize / 2, imgSize, imgSize);
                g.Restore(state);
            }
            else
            {
                g.FillEllipse(Brushes.RoyalBlue, px+2, py+2, CS-4, CS-4);
            }
        }

        private void LoadPoints()
        {
            try
            {
                if (File.Exists(SAVE_PATH))
                {
                    var lines = File.ReadAllLines(SAVE_PATH);
                    if (lines.Length >= 2)
                    {
                        _organicPoints      = Math.Min(MAX_ORGANIC, int.Parse(lines[0].Trim()));
                        _laffPoints         = Math.Min(MAX_LAFF,    int.Parse(lines[1].Trim()));
                        _savedOrganicPoints = _organicPoints; // referência salva
                    }
                }
            }
            catch { }
        }

        private void SavePoints()
        {
            try
            {
                var dir = Path.GetDirectoryName(SAVE_PATH);
                if (!Directory.Exists(dir)) Directory.CreateDirectory(dir);
                File.WriteAllLines(SAVE_PATH, new[]
                {
                    _organicPoints.ToString(),
                    _laffPoints.ToString()
                });
                _savedOrganicPoints = _organicPoints; // atualiza referência após salvar
            }
            catch { }
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _timer?.Dispose();
                _ghostTimer?.Dispose();
                _powerUpTimer?.Dispose();
                _imgPlayer?.Dispose();
                _imgBoss?.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}
